10	export const quote = (items: Array<{ type: string }>, customer: unknown, contractNumber: number): number => {
11	  if (items.length === 0) return PROCESSING_FEE;
12	  const basePremium = BASE_PREMIUMS[items[0].type] ?? 0;
13	  return basePremium + basePremium / 10 + PROCESSING_FEE;
14	};
